+fn table_has_column(conn: &Connection, table: &str, column: &str) -> Result<bool> {
+    let mut stmt = conn
+        .prepare(&format!("PRAGMA table_info({table})"))
+        .map_err(|e| StorageError::Database(e.to_string()))?;
+    let mut rows = stmt
+        .query([])
+        .map_err(|e| StorageError::Database(e.to_string()))?;
+
+    while let Some(row) = rows
+        .next()
+        .map_err(|e| StorageError::Database(e.to_string()))?
+    {
+        let name: String = row
+            .get(1)
+            .map_err(|e| StorageError::Database(e.to_string()))?;
+        if name == column {
+            return Ok(true);
+        }
+    }
+
+    Ok(false)
+}
